"""Тесты AppPath.from_root, resolve_runtime_root, project_root."""from __future__ import annotationsimport osfrom pathlib import Pathimport pytestfrom src.core.app_path import AppPath, project_root, resolve_runtime_rootdef test_from_root_with_explicit_root(tmp_path: Path) -> None:    paths = AppPath.from_root(tmp_path)    assert isinstance(paths, AppPath)    assert paths.root == tmp_path    assert paths.app_ini == tmp_path / "app.ini"    assert paths.logs_dir == tmp_path / "logs"    assert paths.system_log == tmp_path / "logs" / "system.log"    assert paths.data_dir == tmp_path / "data"    assert paths.data_user_dir == tmp_path / "data" / "user"    assert paths.projects_dir == tmp_path / "projects"    assert paths.cache_dir == tmp_path / "cache"    assert paths.temp_dir == tmp_path / "temp"def test_from_root_idempotent_same_root(tmp_path: Path) -> None:    p1 = AppPath.from_root(tmp_path)    p2 = AppPath.from_root(tmp_path)    assert p1.root == p2.root    assert p1.app_ini == p2.app_inidef test_from_root_none_uses_default_root() -> None:    paths = AppPath.from_root()    assert isinstance(paths, AppPath)    assert paths.root.is_absolute()    assert (paths.root / "app.ini") == paths.app_inidef test_resolve_runtime_root_from_source_uses_profile(monkeypatch: pytest.MonkeyPatch) -> None:    monkeypatch.delenv("APP_PROFILE", raising=False)    root = resolve_runtime_root()    assert root == project_root() / "runtime" / "dev"    root_prod = resolve_runtime_root("prod")    assert root_prod == project_root() / "runtime" / "prod"def test_resolve_runtime_root_respects_env(monkeypatch: pytest.MonkeyPatch) -> None:    monkeypatch.setenv("APP_PROFILE", "test")    root = resolve_runtime_root()    assert root == project_root() / "runtime" / "test"def test_project_root_is_absolute() -> None:    assert project_root().is_absolute()    assert (project_root() / "src" / "core").is_dir()